// ──────────────────────────────────────────────────────────────
// ALL-IN-ONE RAG Chat: embed question → search Qdrant → ask LLM
// Uses 127.0.0.1 instead of localhost to avoid IPv6 issues
// ──────────────────────────────────────────────────────────────

const OLLAMA = 'http://127.0.0.1:11434';
const QDRANT = 'http://127.0.0.1:6333';
const EMBED_MODEL = 'nomic-embed-text';
const CHAT_MODEL = 'gemma2:2b';
const COLLECTION = 'pdf_rag';
const SCORE_THRESHOLD = 0.3;
const TOP_K = 5;

const item = $input.first();
const question = (item.json.body?.question || item.json.question || '').trim();
const fileFilter = item.json.body?.file_filter || item.json.file_filter || null;

if (!question || question.length < 3) {
  return [{ json: { error: 'Please provide a question (min 3 chars)' } }];
}

try {
  // 1. Embed the question
  const embedResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OLLAMA}/api/embeddings`,
    body: { model: EMBED_MODEL, prompt: question },
    headers: { 'Content-Type': 'application/json' },
    timeout: 60000
  });

  if (!embedResp.embedding) {
    return [{ json: { question, answer: 'Error: Could not generate embedding.', sources: '' } }];
  }

  // 2. Search Qdrant
  const searchPayload = {
    vector: embedResp.embedding,
    limit: TOP_K,
    score_threshold: SCORE_THRESHOLD,
    with_payload: true,
    with_vector: false
  };

  if (fileFilter) {
    searchPayload.filter = { must: [{ key: 'file_name', match: { value: fileFilter } }] };
  }

  const searchResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${QDRANT}/collections/${COLLECTION}/points/search`,
    body: searchPayload,
    headers: { 'Content-Type': 'application/json' },
    timeout: 30000
  });

  const results = (searchResp.result || []).filter(r => r.score >= SCORE_THRESHOLD);

  // 3. No context? Return early
  if (results.length === 0) {
    return [{ json: {
      question,
      answer: 'I could not find this information in the uploaded document.',
      sources: 'No relevant context found',
      chunks_retrieved: 0
    }}];
  }

  // 4. Build context
  const contextParts = [];
  const sources = [];
  for (const r of results) {
    const p = r.payload;
    const score = r.score.toFixed(3);
    contextParts.push(`[Source: ${p.file_name}, Chunk ${p.chunk_index + 1}/${p.total_chunks}, Score: ${score}]\n${p.text}`);
    sources.push(`${p.file_name} (Chunk ${p.chunk_index + 1}, Score: ${score})`);
  }
  const context = contextParts.join('\n\n---\n\n');

  // 5. Ask LLM
  const systemPrompt = 'You are a precise document assistant. You MUST answer questions ONLY using the provided context. STRICT RULES: 1) NEVER use general knowledge. 2) NEVER invent facts. 3) If the answer is not in context, respond: I could not find this information in the uploaded document. 4) Mention source file and chunk number. 5) Be concise. 6) Quote from context when possible.';

  const GEMINI_API_KEY = process.env.GEMINI_API_KEY || 'SET_YOUR_KEY_IN_ENV';
  const geminiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_API_KEY}`;

  const chatResp = await this.helpers.httpRequest({
    method: 'POST',
    url: geminiUrl,
    body: {
      contents: [{
        role: "user",
        parts: [{ text: systemPrompt + "\n\nContext:\n\n" + context + "\n\n---\n\nQuestion: " + question + "\n\nAnswer based ONLY on the above context." }]
      }],
      generationConfig: { temperature: 0.1 }
    },
    headers: { 'Content-Type': 'application/json' },
    timeout: 120000
  });

  const answer = chatResp.candidates?.[0]?.content?.parts?.[0]?.text || 'Error: No response from Gemini.';

  return [{ json: {
    question,
    answer,
    sources: sources.join('\n'),
    chunks_retrieved: results.length
  }}];

} catch (e) {
  return [{ json: {
    question,
    answer: `Error: ${e.message}`,
    sources: '',
    chunks_retrieved: 0
  }}];
}
